UPDATE t_p45929761_bold_move_project.ai_system_prompt
SET content = REPLACE(content,
E'Количество бери из данных помещения (периметр, площадь, длины стен), а не придумывай.\n\nПРАВИЛО 0',
E'Количество бери из данных помещения (периметр, площадь, длины стен), а не придумывай.\n\nКРИТИЧЕСКИ ВАЖНО — ОДИН ТОВАР НА НЕСКОЛЬКО СТЕН:\nЕсли один и тот же товар упомянут на нескольких стенах (например «слева ниша ПК-14 и справа ниша ПК-14») —\nВОЗВРАЩАЙ ЕГО НЕСКОЛЬКО РАЗ, отдельной строкой для каждой стены, с qty = длина ЭТОЙ стены.\nНЕ суммируй в одну строку — каждая стена = отдельный объект в массиве items.\nПример: слева 3.5м ниша ПК-14, справа 3.5м ниша ПК-14 →\n  {\"name\":\"Ниша ПК-14 (2 ряда)\",\"qty\":3.5,\"wall\":\"left\"},\n  {\"name\":\"Ниша ПК-14 (2 ряда)\",\"qty\":3.5,\"wall\":\"right\"}\nАналогично для стенового профиля, теневого и любого другого товара на нескольких стенах.\n\nПРАВИЛО 0')
WHERE id = 1